import { Collapsible as CollapsiblePrimitive, useCollapsible } from '@ark-ui/react/collapsible';
import { ark, type HTMLArkProps } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { ChevronDownIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Collapsible.module.css';

const CollapsibleRoot = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Root>,
  ComponentProps<typeof CollapsiblePrimitive.Root>
>(function CollapsibleRoot({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Root
      ref={ref}
      data-slot="collapsible-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const CollapsibleRootProvider = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.RootProvider>,
  ComponentProps<typeof CollapsiblePrimitive.RootProvider>
>(function CollapsibleRootProvider({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.RootProvider
      ref={ref}
      data-slot="collapsible-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const CollapsibleTrigger = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Trigger>,
  ComponentProps<typeof CollapsiblePrimitive.Trigger>
>(function CollapsibleTrigger({ asChild, className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Trigger
      ref={ref}
      asChild={asChild}
      data-slot="collapsible-trigger"
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const CollapsibleIndicator = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Indicator>,
  ComponentProps<typeof CollapsiblePrimitive.Indicator>
>(function CollapsibleIndicator({ className, children, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Indicator
      ref={ref}
      data-slot="collapsible-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <ChevronDownIcon />}
    </CollapsiblePrimitive.Indicator>
  );
});

const CollapsibleContent = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Content>,
  ComponentProps<typeof CollapsiblePrimitive.Content>
>(function CollapsibleContent({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Content
      ref={ref}
      data-slot="collapsible-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const CollapsibleBody = forwardRef<ComponentRef<typeof ark.div>, HTMLArkProps<'div'>>(
  function CollapsibleBody({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="collapsible"
        data-part="body"
        data-slot="collapsible-body"
        className={clsx(styles.body, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const Collapsible = Object.assign(CollapsibleRoot, {
  Root: CollapsibleRoot,
  RootProvider: CollapsibleRootProvider,
  Trigger: CollapsibleTrigger,
  Indicator: CollapsibleIndicator,
  Content: CollapsibleContent,
  Body: CollapsibleBody,
});

export { Collapsible, useCollapsible };

@layer moduix.components {
  @keyframes collapsible-content-open {
    from {
      height: var(--collapsed-height, 0);
      width: var(--collapsed-width, var(--width));
      opacity: var(--moduix-collapsible-content-closed-opacity, 0.01);
    }

    to {
      height: var(--height);
      width: var(--width);
      opacity: var(--moduix-collapsible-content-open-opacity, 1);
    }
  }

  @keyframes collapsible-content-closed {
    from {
      height: var(--height);
      width: var(--width);
      opacity: var(--moduix-collapsible-content-open-opacity, 1);
    }

    to {
      height: var(--collapsed-height, 0);
      width: var(--collapsed-width, var(--width));
      opacity: var(--moduix-collapsible-content-closed-opacity, 0.01);
    }
  }

  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--moduix-collapsible-width, 100%);
    max-width: var(--moduix-collapsible-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    color: var(--moduix-collapsible-color, var(--moduix-color-foreground));
  }

  .trigger {
    box-sizing: border-box;
    display: flex;
    width: 100%;
    align-items: center;
    justify-content: space-between;
    gap: var(--moduix-collapsible-trigger-gap, var(--moduix-spacing-2));
    margin: 0;
    border: 0;
    border-radius: var(--moduix-collapsible-trigger-radius, 0);
    padding-block: var(--moduix-collapsible-trigger-padding-y, var(--moduix-spacing-1));
    padding-inline: var(--moduix-collapsible-trigger-padding-x, var(--moduix-spacing-2));
    background-color: var(--moduix-collapsible-trigger-bg, transparent);
    color: var(
      --moduix-collapsible-trigger-color,
      var(--moduix-collapsible-color, var(--moduix-color-foreground))
    );
    font: inherit;
    font-size: var(--moduix-collapsible-trigger-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-collapsible-trigger-line-height, var(--moduix-line-height-text-sm));
    text-align: left;
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color
        var(--moduix-collapsible-trigger-transition, var(--moduix-transition-default)),
      color var(--moduix-collapsible-trigger-transition, var(--moduix-transition-default));

    &:focus-visible {
      outline: var(
          --moduix-collapsible-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        )
        solid var(--moduix-collapsible-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-collapsible-focus-ring-offset, var(--moduix-border-width-sm));
    }

    &:not(:is([disabled], [data-disabled])) {
      @media (hover: hover) {
        &:hover {
          background-color: var(
            --moduix-collapsible-trigger-bg-hover,
            var(--moduix-collapsible-trigger-bg, transparent)
          );
        }
      }

      &:active {
        background-color: var(
          --moduix-collapsible-trigger-bg-active,
          var(
            --moduix-collapsible-trigger-bg-hover,
            var(--moduix-collapsible-trigger-bg, transparent)
          )
        );
      }
    }

    &:is([disabled], [data-disabled]) {
      opacity: var(--moduix-collapsible-disabled-opacity, var(--moduix-opacity-disabled));
      cursor: default;
    }
  }

  .indicator {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--moduix-collapsible-indicator-size, var(--moduix-spacing-3));
    height: var(--moduix-collapsible-indicator-size, var(--moduix-spacing-3));
    flex-shrink: 0;
    transition: transform
      var(--moduix-collapsible-indicator-transition, var(--moduix-transition-default));

    & > svg {
      width: 100%;
      height: 100%;
    }

    &[data-state='open'] {
      transform: var(--moduix-collapsible-indicator-open-transform, rotate(180deg));
    }

    &[data-disabled] {
      opacity: var(--moduix-collapsible-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .content {
    --collapsed-height: 0;

    box-sizing: border-box;
    overflow: hidden;
    color: var(--moduix-collapsible-content-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-collapsible-content-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-collapsible-content-line-height, var(--moduix-line-height-text-sm));

    &[data-state='open'] {
      animation: collapsible-content-open
        var(--moduix-collapsible-content-transition, var(--moduix-transition-default));

      &[data-has-collapsed-size] {
        --moduix-collapsible-content-closed-opacity: var(
          --moduix-collapsible-content-open-opacity,
          1
        );
      }
    }

    &[data-state='closed'] {
      animation: collapsible-content-closed
        var(--moduix-collapsible-content-transition, var(--moduix-transition-default));

      &[data-has-collapsed-size] {
        --moduix-collapsible-content-closed-opacity: var(
          --moduix-collapsible-content-open-opacity,
          1
        );
      }
    }
  }

  .body {
    display: grid;
    gap: var(--moduix-collapsible-body-gap, var(--moduix-spacing-2));
    min-width: 0;
    padding: var(--moduix-collapsible-body-padding, var(--moduix-spacing-2));
  }
}
